<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Arial, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    flex-direction: column;
  }
  h1 { font-size: 2.5rem; margin-bottom: 0.25rem; color: #f0e68c; }
  #score {
    font-size: 1.4rem;
    margin-bottom: 0.75rem;
    background: #16213e;
    padding: 0.4rem 1.2rem;
    border-radius: 8px;
    min-width: 120px;
    text-align: center;
  }
  #reset {
    margin-bottom: 1rem;
    padding: 0.5rem 1.5rem;
    font-size: 1rem;
    background: #e94560;
    color: #fff;
    border: none;
    border-radius: 6px;
    cursor: pointer;
  }
  #reset:hover { background: #c73650; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 8px;
    background: #16213e;
    padding: 10px;
    border-radius: 10px;
    width: 340px;
    height: 340px;
  }
  .cell {
    background: #0f3460;
    border-radius: 6px;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 1.8rem;
    font-weight: bold;
    color: #eee;
    user-select: none;
  }
  .cell[data-value="0"] { background: #0a1628; color: transparent; }
  .cell[data-value="2"]   { background: #1a3a5c; color: #e0e0e0; }
  .cell[data-value="4"]   { background: #1e4d6e; color: #e0e0e0; }
  .cell[data-value="8"]   { background: #2a649a; color: #fff; }
  .cell[data-value="16"]  { background: #3a7cb8; color: #fff; }
  .cell[data-value="32"]  { background: #4a90d0; color: #fff; }
  .cell[data-value="64"]  { background: #e94560; color: #fff; }
  .cell[data-value="128"] { background: #f0a030; color: #fff; font-size: 1.6rem; }
  .cell[data-value="256"] { background: #f0b040; color: #fff; font-size: 1.6rem; }
  .cell[data-value="512"] { background: #f0c050; color: #fff; font-size: 1.6rem; }
  .cell[data-value="1024"]{ background: #f0d060; color: #fff; font-size: 1.3rem; }
  .cell[data-value="2048"]{ background: #f0e070; color: #fff; font-size: 1.3rem; }
  .cell[data-value] { box-shadow: 0 0 8px rgba(255,255,255,0.15); }
</style>
</head>
<body>
<h1>2048</h1>
<div id="score">Score: 0</div>
<button id="reset">New Game</button>
<div id="board"></div>

<script>
(function() {
  const SIZE = 4;
  let board = [];
  let score = 0;

  function createBoard() {
    const el = document.getElementById('board');
    el.innerHTML = '';
    for (let i = 0; i < SIZE * SIZE; i++) {
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.dataset.value = '0';
      cell.textContent = '';
      el.appendChild(cell);
    }
  }

  function render() {
    const cells = document.getElementById('board').children;
    for (let i = 0; i < SIZE * SIZE; i++) {
      const val = board[Math.floor(i / SIZE)][i % SIZE];
      cells[i].dataset.value = val;
      cells[i].textContent = val === 0 ? '' : val;
    }
    document.getElementById('score').textContent = 'Score: ' + score;
  }

  function cloneBoard(b) {
    return b.map(function(row) { return row.slice(); });
  }

  function isEmpty(b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (b[r][c] !== 0) return false;
    return true;
  }

  function getEmptyCells(b) {
    var cells = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (b[r][c] === 0) cells.push([r, c]);
    return cells;
  }

  function slideAndMergeLine(line) {
    // Remove zeros, slide to front
    var filtered = line.filter(function(v) { return v !== 0; });
    var merged = [];
    var i = 0;
    var gained = 0;
    while (i < filtered.length) {
      if (i + 1 < filtered.length && filtered[i] === filtered[i + 1]) {
        var newVal = filtered[i] * 2;
        merged.push(newVal);
        gained += newVal;
        i += 2;
      } else {
        merged.push(filtered[i]);
        i++;
      }
    }
    // Pad with zeros
    while (merged.length < SIZE) merged.push(0);
    return { result: merged, gained: gained };
  }

  function move(direction) {
    var oldBoard = cloneBoard(board);
    var totalGained = 0;

    if (direction === 'left') {
      for (let r = 0; r < SIZE; r++) {
        var line = board[r].slice();
        var res = slideAndMergeLine(line);
        board[r] = res.result;
        totalGained += res.gained;
      }
    } else if (direction === 'right') {
      for (let r = 0; r < SIZE; r++) {
        var line = board[r].slice().reverse();
        var res = slideAndMergeLine(line);
        board[r] = res.result.reverse();
        totalGained += res.gained;
      }
    } else if (direction === 'up') {
      for (let c = 0; c < SIZE; c++) {
        var col = [];
        for (let r = 0; r < SIZE; r++) col.push(board[r][c]);
        var res = slideAndMergeLine(col);
        for (let r = 0; r < SIZE; r++) board[r][c] = res.result[r];
        totalGained += res.gained;
      }
    } else if (direction === 'down') {
      for (let c = 0; c < SIZE; c++) {
        var col = [];
        for (let r = 0; r < SIZE; r++) col.push(board[r][c]);
        var res = slideAndMergeLine(col.reverse());
        var rev = res.result.reverse();
        for (let r = 0; r < SIZE; r++) board[r][c] = rev[r];
        totalGained += res.gained;
      }
    }

    var changed = false;
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (board[r][c] !== oldBoard[r][c]) changed = true;

    if (changed) {
      score += totalGained;
      // Spawn new tile
      var empty = getEmptyCells(board);
      if (empty.length > 0) {
        var cell = empty[Math.floor(Math.random() * empty.length)];
        board[cell[0]][cell[1]] = Math.random() < 0.9 ? 2 : 4;
      }
    }

    render();
    return changed;
  }

  function reset() {
    board = [];
    for (let r = 0; r < SIZE; r++) {
      board.push([]);
      for (let c = 0; c < SIZE; c++) {
        board[r].push(0);
      }
    }
    score = 0;
    // Place exactly 2 tiles
    var empty = getEmptyCells(board);
    var c1 = empty[Math.floor(Math.random() * empty.length)];
    board[c1[0]][c1[1]] = 2;
    empty = getEmptyCells(board);
    var c2 = empty[Math.floor(Math.random() * empty.length)];
    board[c2[0]][c2[1]] = Math.random() < 0.9 ? 2 : 4;
    render();
  }

  function setBoard(arr) {
    board = arr.map(function(row) { return row.slice(); });
    render();
  }

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: function() { return board.map(function(row) { return row.slice(); }); },
    setBoard: setBoard,
    score: function() { return score; }
  };

  document.getElementById('reset').addEventListener('click', reset);

  document.addEventListener('keydown', function(e) {
    var map = {
      'ArrowLeft': 'left',
      'ArrowRight': 'right',
      'ArrowUp': 'up',
      'ArrowDown': 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      window.game.move(map[e.key]);
    }
  });

  createBoard();
  reset();
})();
</script>
</body>
</html>
